import React, { useEffect, useState } from 'react';
import TopTemplate from './TopTemplate';
import axios from 'axios';

const TopverkopersDrank = () => {
    const [data, setData] = useState(null);
    const [error, setError] = useState(null);

    useEffect(() => {
        axios.get('http://localhost:3007/api/sales', { withCredentials: true })
            .then(res => {
                const sorted = [...res.data].sort((a, b) => b.total_sold - a.total_sold);
                const topItems = sorted.slice(0, 5).map(i => ({
                    name: i.item_name,
                    brand: i.producent,
                    sales: i.total_sold
                }));
                const bottomItems = sorted.slice(-5).reverse().map(i => ({
                    name: i.item_name,
                    brand: i.producent,
                    sales: i.total_sold
                }));
                setData({
                    topTitle: "Top 5 Bestsellers",
                    topSubtitle: "De meest verkochte items van de laatste 90 dagen",
                    topItems,
                    bottomTitle: "Minst Verkochte",
                    bottomSubtitle: "Deze items verkochten het minst",
                    bottomItems
                });
            })
            .catch(err => {
                console.error(err);
                setError("Kon verkoopdata niet laden");
            });
    }, []);

    if (error) return <h1>{error}</h1>;
    if (!data) return <p>Loading…</p>;

    return (
        <TopTemplate
            topTitle={data.topTitle}
            topSubtitle={data.topSubtitle}
            topItems={data.topItems}
            bottomTitle={data.bottomTitle}
            bottomSubtitle={data.bottomSubtitle}
            bottomItems={data.bottomItems}
        />
    );
};

export default TopverkopersDrank;
